#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
  long x = *(const long *)a, y = *(const long *)b;
  return (x > y) - (x < y);
}

int main(void) {
  int n;
  if (scanf("%d", &n) != 1 || n <= 0) return 0;
  long t[1024], q[1024];
  for (int i = 0; i < n; i++) scanf("%ld", &t[i]);
  for (int i = 0; i < n; i++) scanf("%ld", &q[i]);
  qsort(t, (size_t)n, sizeof(t[0]), cmp);
  qsort(q, (size_t)n, sizeof(q[0]), cmp);
  int i = 0, j = n - 1, k = 0, l = n - 1;
  long long money = 0;
  for (int r = 0; r < n; r++) {
    if (t[j] > q[l]) { money += 200; j--; l--; }
    else if (t[i] > q[k]) { money += 200; i++; k++; }
    else {
      if (t[i] < q[k]) money -= 200;
      i++; k++;
    }
  }
  printf("%lld\n", money);
  return 0;
}
